en und Lessons Learned Qualifikation Abgeschlossenes Studium im Ingenieurwesen, Wirtschaftsingenieurwesen, Maschinenbau oder vergleichbar meh", "skills_required": ["Engineering"], "work_mode": "REMOTE", "employment_type": "EMPLOYED", "external_url": "https://www.arbeitnow.com/jobs/companies/remmert-gmbh/senior-projektleiter-anlagenbau-gn-minden-112023"}'::jsonb, 'US', true, '[0.01423301,1.71433985,3.53620362,0.48090109,-0.06124187,-0.86025524,-0.26774108,0.46085462,-0.77191818,-2.14026356,-0.35794857,2.21586609,-0.88589543,-2.45499921,-0.60233796,5.92185068,0.29851577,-0.27810165,-1.57034039,-0.61236626,-0.28785408,-4.47067022,-0.29512522,-2.38385057,-5.55194712,-2.19659376,-0.53407121,1.66032410,-1.89739990,-6.52811193,1.25188828,-1.17220116,-1.58670115,-3.67423153,0.64256442,-2.46717453,3.47100401,-0.95141309,0.66112089,3.64793253,0.03482396,1.77742016,-2.48446679,1.68195426,4.87239122,-2.32611394,-3.77221036,-0.69506711,1.23962629,2.85889077,0.17534527,0.22008392,-0.80001181,-0.67390698,-2.96696210,-4.25695086,0.19753830,0.99725699,-3.09171152,-0.63148451,5.47530699,-1.71351969,0.65307039,1.05637753,0.29964492,-1.27970243,-0.01602930,0.43261459,0.98550391,-0.99108815,2.12657166,0.47644144,1.33733439,-1.78482831,3.78027105,1.06276679,-0.77569366,-1.88502777,1.75159967,1.32693505,-3.64153457,-2.18482232,-3.53958797,-1.65943062,2.79456997,-2.14173341,-2.27651620,-0.62290543,0.60184997,6.38641024,1.60881162,-2.12553120,2.47151327,-1.32114053,-1.56367195,-0.42610779,-8.14933777,-1.30292881,-6.35230875,0.37445563,0.00181105,-2.12156582,-0.53049678,-2.80054140,-1.82839167,0.18282560,-0.16185148,6.80200195,2.65514421,-3.52857590,-1.79784179,3.41381121,-1.18407023,1.08648241,-6.52480507,3.99382377,4.20343828,0.60383755,-3.33051705,-3.06096339,0.19248663,0.50342727,-1.32487202,-1.61394131,4.96389914,-0.44949356,-0.31069383,2.02523327,0.77420515,-2.39676332,2.47225952,3.05853868,-4.89779091,-5.25498676,-2.27762890,-0.51500213,-1.76891923,-2.77249789,4.16756296,1.44145858,-0