en und Lessons Learned Qualifikation Abgeschlossenes Studium im Ingenieurwesen, Wirtschaftsingenieurwesen, Maschinenbau oder vergleichbar meh", "skills_required": ["Engineering"], "work_mode": "HYBRID", "employment_type": "FREELANCE", "external_url": "https://www.arbeitnow.com/jobs/companies/remmert-gmbh/senior-projektleiter-anlagenbau-gn-lubbecke-341370"}'::jsonb, 'DE', true, '[0.26598179,1.55158603,3.54293060,0.40300098,0.10761613,-0.96418899,-0.13058196,0.24860831,-0.91187179,-2.13385820,-0.37395516,2.34566426,-1.21465337,-2.24685025,-0.66348267,5.66500807,0.25761074,-0.22816156,-1.18073285,-0.50949669,-0.08408819,-4.40841484,-0.48960447,-1.92463756,-5.70622492,-2.06420922,-0.49560082,1.78438878,-2.06729770,-6.58014488,1.21072209,-1.29903567,-1.40821373,-3.73448682,0.73311341,-2.30218053,3.40483141,-0.39712572,0.71372247,3.82030535,0.08383407,1.66806638,-2.77446270,1.82892847,4.76322746,-2.38355422,-3.81211114,-0.68724895,0.85006291,3.06631827,0.22142290,0.16197222,-0.88264406,-0.65571249,-2.98067451,-4.51436663,0.11511971,1.08339119,-2.99430537,-0.29632533,5.58146811,-1.97135532,0.42075413,1.04182696,0.15594676,-1.27532768,0.01376363,0.31254333,1.43968725,-1.40640748,2.40921903,0.25323611,1.21728110,-1.79379308,3.80991173,1.07116807,-0.80468327,-1.90949094,1.49462736,1.20303464,-3.73664045,-2.07118726,-3.62373161,-1.75912166,2.78761101,-2.04694939,-2.05538726,-0.28996104,1.24194777,6.25596952,1.43474042,-1.64237070,2.54739094,-1.12887180,-1.70182133,-0.30473730,-8.06491470,-1.44573748,-6.32809448,0.37741795,0.20699027,-1.78452241,-0.76078308,-2.62809205,-1.95176387,0.02398302,-0.38502923,6.85515594,2.45775890,-3.55677485,-1.62304258,3.36441350,-1.17164791,0.95217699,-6.39749527,4.16198540,4.28072309,0.35341749,-3.50754237,-2.74021196,0.23651567,0.52679086,-1.15658760,-1.69039845,4.87771654,-0.45614690,-0.34396213,1.95505929,0.26202172,-2.51098418,2.44547868,3.15038514,-4.77588797,-5.35326481,-2.47599745,-0.80438954,-1.78939581,-2.71946859,4.12197065,1.66144347,-